<?php/** * AquaLuxe General Helper Functions * * @package AquaLuxe */if (!defined('ABSPATH')) {    exit; // Exit if accessed directly.}/** * Sanitize checkbox * * @param bool $input Input value * @return bool */function aqualuxe_sanitize_checkbox($input) {    return (isset($input) && true === $input) ? true : false;}/** * Sanitize select * * @param string $input Input value * @param object $setting Setting object * @return string */function aqualuxe_sanitize_select($input, $setting) {    // Get the list of choices from the control associated with the setting    $choices = $setting->manager->get_control($setting->id)->choices;        // Return input if valid or return default option    return (array_key_exists($input, $choices) ? $input : $setting->default);}/** * Sanitize hex color * * @param string $color Color value * @return string */function aqualuxe_sanitize_hex_color($color) {    if ('' === $color) {        return '';    }        // 3 or 6 hex digits, or the empty string.    if (preg_match('|^#([A-Fa-f0-9]{3}){1,2}$|', $color)) {        return $color;    }        return '';}/** * Sanitize rgba color * * @param string $color Color value * @return string */function aqualuxe_sanitize_rgba_color($color) {    if ('' === $color) {        return '';    }        // Check if it's a hex color    if (preg_match('|^#([A-Fa-f0-9]{3}){1,2}$|', $color)) {        return $color;    }        // Check if it's an rgba color    if (preg_match('/^rgba\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d*(?:\.\d+)?)\s*\)$/', $color, $matches)) {        $red   = $matches[1] >= 0 && $matches[1] <= 255 ? $matches[1] : 0;        $green = $matches[2] >= 0 && $matches[2] <= 255 ? $matches[2] : 0;        $blue  = $matches[3] >= 0 && $matches[3] <= 255 ? $matches[3] : 0;        $alpha = $matches[4] >= 0 && $matches[4] <= 1 ? $matches[4] : 1;                return "rgba($red, $green, $blue, $alpha)";    }        return '';}/** * Convert hex color to rgba * * @param string $color Hex color * @param float $opacity Opacity * @return string */function aqualuxe_hex_to_rgba($color, $opacity = 1) {    $default = 'rgba(0, 0, 0, 1)';        // Return default if no color provided    if (empty($color)) {        return $default;    }        // Sanitize $color if "#" is provided    if ($color[0] == '#') {        $color = substr($color, 1);    }        // Check if color has 6 or 3 characters and get values    if (strlen($color) == 6) {        $hex = [$color[0] . $color[1], $color[2] . $color[3], $color[4] . $color[5]];    } elseif (strlen($color) == 3) {        $hex = [$color[0] . $color[0], $color[1] . $color[1], $color[2] . $color[2]];    } else {        return $default;    }        // Convert hexadec to rgb    $rgb = array_map('hexdec', $hex);        // Check if opacity is set(rgba or rgb)    if ($opacity) {        if (abs($opacity) > 1) {            $opacity = 1.0;        }        $output = 'rgba(' . implode(',', $rgb) . ',' . $opacity . ')';    } else {        $output = 'rgb(' . implode(',', $rgb) . ')';    }        // Return rgb(a) color string    return $output;}/** * Get theme mod with default * * @param string $name Theme mod name * @param mixed $default Default value * @return mixed */function aqualuxe_get_theme_mod($name, $default = '') {    return get_theme_mod($name, $default);}/** * Check if WooCommerce is active * * @return bool */function aqualuxe_is_woocommerce_active() {    return aqualuxe()->is_woocommerce_active();}/** * Check if module is active * * @param string $module_name Module name * @return bool */function aqualuxe_is_module_active($module_name) {    return aqualuxe()->is_module_active($module_name);}/** * Get module * * @param string $module_name Module name * @return object|null */function aqualuxe_get_module($module_name) {    return aqualuxe()->get_module($module_name);}/** * Get current language * * @return string */function aqualuxe_get_current_language() {    // Check if WPML is active    if (defined('ICL_LANGUAGE_CODE')) {        return ICL_LANGUAGE_CODE;    }        // Check if Polylang is active    if (function_exists('pll_current_language')) {        return pll_current_language();    }        // Default to WordPress locale    return get_locale();}/** * Get languages * * @return array */function aqualuxe_get_languages() {    $languages = [];        // Check if WPML is active    if (function_exists('icl_get_languages')) {        $wpml_languages = icl_get_languages('skip_missing=0&orderby=code');                if (!empty($wpml_languages)) {            foreach ($wpml_languages as $language) {                $languages[$language['language_code']] = [                    'code'      => $language['language_code'],                    'name'      => $language['native_name'],                    'flag'      => $language['country_flag_url'],                    'url'       => $language['url'],                    'active'    => $language['active'],                ];            }        }    }        // Check if Polylang is active    if (function_exists('pll_languages_list')) {        $pll_languages = pll_languages_list(['fields' => '']);                if (!empty($pll_languages)) {            foreach ($pll_languages as $language) {                $languages[$language->slug] = [                    'code'      => $language->slug,                    'name'      => $language->name,                    'flag'      => $language->flag_url,                    'url'       => $language->home_url,                    'active'    => $language->slug === pll_current_language(),                ];            }        }    }        return $languages;}/** * Get currency symbol * * @param string $currency Currency code * @return string */function aqualuxe_get_currency_symbol($currency = '') {    if (empty($currency)) {        // Get WooCommerce currency if WooCommerce is active        if (aqualuxe_is_woocommerce_active() && function_exists('get_woocommerce_currency')) {            $currency = get_woocommerce_currency();        } else {            $currency = 'USD';        }    }        $symbols = [        'AED' => 'د.إ',        'AFN' => '؋',        'ALL' => 'L',        'AMD' => '֏',        'ANG' => 'ƒ',        'AOA' => 'Kz',        'ARS' => '$',        'AUD' => '$',        'AWG' => 'ƒ',        'AZN' => '₼',        'BAM' => 'KM',        'BBD' => '$',        'BDT' => '৳',        'BGN' => 'лв',        'BHD' => '.د.ب',        'BIF' => 'FBu',        'BMD' => '$',        'BND' => '$',        'BOB' => 'Bs.',        'BRL' => 'R$',        'BSD' => '$',        'BTC' => '₿',        'BTN' => 'Nu.',        'BWP' => 'P',        'BYN' => 'Br',        'BYR' => 'Br',        'BZD' => 'BZ$',        'CAD' => '$',        'CDF' => 'FC',        'CHF' => 'CHF',        'CLP' => '$',        'CNY' => '¥',        'COP' => '$',        'CRC' => '₡',        'CUC' => '$',        'CUP' => '₱',        'CVE' => '$',        'CZK' => 'Kč',        'DJF' => 'Fdj',        'DKK' => 'kr',        'DOP' => 'RD$',        'DZD' => 'دج',        'EGP' => 'EGP',        'ERN' => 'Nfk',        'ETB' => 'Br',        'EUR' => '€',        'FJD' => '$',        'FKP' => '£',        'GBP' => '£',        'GEL' => '₾',        'GGP' => '£',        'GHS' => '₵',        'GIP' => '£',        'GMD' => 'D',        'GNF' => 'FG',        'GTQ' => 'Q',        'GYD' => '$',        'HKD' => '$',        'HNL' => 'L',        'HRK' => 'kn',        'HTG' => 'G',        'HUF' => 'Ft',        'IDR' => 'Rp',        'ILS' => '₪',        'IMP' => '£',        'INR' => '₹',        'IQD' => 'ع.د',        'IRR' => '﷼',        'ISK' => 'kr',        'JEP' => '£',        'JMD' => 'J$',        'JOD' => 'JD',        'JPY' => '¥',        'KES' => 'KSh',        'KGS' => 'с',        'KHR' => '៛',        'KMF' => 'CF',        'KPW' => '₩',        'KRW' => '₩',        'KWD' => 'KD',        'KYD' => '$',        'KZT' => '₸',        'LAK' => '₭',        'LBP' => 'ل.ل',        'LKR' => 'Rs',        'LRD' => '$',        'LSL' => 'L',        'LYD' => 'ل.د',        'MAD' => 'د.م.',        'MDL' => 'L',        'MGA' => 'Ar',        'MKD' => 'ден',        'MMK' => 'Ks',        'MNT' => '₮',        'MOP' => 'MOP$',        'MRO' => 'UM',        'MRU' => 'UM',        'MUR' => '₨',        'MVR' => '.ރ',        'MWK' => 'MK',        'MXN' => '$',        'MYR' => 'RM',        'MZN' => 'MT',        'NAD' => '$',        'NGN' => '₦',        'NIO' => 'C$',        'NOK' => 'kr',        'NPR' => '₨',        'NZD' => '$',        'OMR' => 'ر.ع.',        'PAB' => 'B/.',        'PEN' => 'S/',        'PGK' => 'K',        'PHP' => '₱',        'PKR' => '₨',        'PLN' => 'zł',        'PRB' => 'р.',        'PYG' => '₲',        'QAR' => 'ر.ق',        'RON' => 'lei',        'RSD' => 'дин',        'RUB' => '₽',        'RWF' => 'R₣',        'SAR' => 'ر.س',        'SBD' => '$',        'SCR' => '₨',        'SDG' => 'ج.س.',        'SEK' => 'kr',        'SGD' => '$',        'SHP' => '£',        'SLL' => 'Le',        'SOS' => 'Sh',        'SRD' => '$',        'SSP' => '£',        'STD' => 'Db',        'STN' => 'Db',        'SYP' => '£',        'SZL' => 'L',        'THB' => '฿',        'TJS' => 'ЅМ',        'TMT' => 'm',        'TND' => 'د.ت',        'TOP' => 'T$',        'TRY' => '₺',        'TTD' => '$',        'TVD' => '$',        'TWD' => 'NT$',        'TZS' => 'Sh',        'UAH' => '₴',        'UGX' => 'UGX',        'USD' => '$',        'UYU' => '$',        'UZS' => 'лв',        'VEF' => 'Bs',        'VES' => 'Bs.S',        'VND' => '₫',        'VUV' => 'VT',        'WST' => 'WS$',        'XAF' => 'FCFA',        'XCD' => '$',        'XOF' => 'CFA',        'XPF' => '₣',        'YER' => '﷼',        'ZAR' => 'R',        'ZMW' => 'ZK',    ];        return isset($symbols[$currency]) ? $symbols[$currency] : '';}